// ShaderLab Custom — Sphere
uniform vec3  uColor;
uniform float uBright,uEdge;
uniform float uLodFade;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.464)discard;if(0.0>0.005&&d<0.0)discard;alpha=1.0-smoothstep(0.398,0.464,d);}
  col=uColor*(0.4*(0.302+vBlink*0.032));
  col=pow(max(col*vec3(0.73,0.73,0.69),vec3(0.0)),vec3(1.0/1.04));
  {float _f=pow(clamp(1.0-abs(vPhase-0.5)*2.0,0.0,1.0),2.17);col+=_f*0.98*vec3(0.75,0.73,0.66);col+=clamp(1.0-_f,0.0,1.0)*col*0.27;}
  alpha=pow(max(alpha,0.0),1.1)*0.76+0.001;
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0)*uLodFade);
}
